const msg = $input.first().json;
const content = msg.content || '';
const channelId = msg.channelId || msg.channel_id;

let mode = 'team';
let task = content;

if (content.startsWith('$ralph')) {
  mode = 'ralph';
  task = content.replace(/^\$ralph\s*/, '').trim();
} else if (content.startsWith('$team')) {
  mode = 'team';
  task = content.replace(/^\$team\s*/, '').trim();
}

// Extract repo (owner/repo)
const repoMatch = task.match(/(?:in|for|on)\s+(\S+\/\S+)/i);
const repository = repoMatch ? repoMatch[1] : null;
if (repoMatch) task = task.replace(repoMatch[0], '').trim();
task = task.replace(/^["']|["']$/g, '').trim();

return {
  json: {
    mode,
    task,
    repository,
    channelId,
    author: msg.author?.username || 'unknown',
    maxRetries: mode === 'ralph' ? 3 : 0
  }
};

