const cmd = $('Build Context').first().json;
const resp = $input.first().json;
const text = resp.content?.[0]?.text || '';

let plan;
try {
  const jsonMatch = text.match(/```(?:json)?\n?([\s\S]*?)\n?```/);
  plan = JSON.parse(jsonMatch ? jsonMatch[1] : text);
} catch (e) {
  plan = {
    task_summary: cmd.task,
    branch_name: 'feature/auto-' + Date.now(),
    steps: [{
      step_id: 1,
      action: 'create',
      target_file: 'output.txt',
      description: text.slice(0, 500),
      acceptance_criteria: ['Implementation matches description']
    }]
  };
}

const verification = plan.verification || { commands: [], expected_outcomes: [] };

// Output one item per step for looping
return plan.steps.map((step, i) => ({
  json: {
    ...cmd,
    plan_summary: plan.task_summary,
    branch_name: plan.branch_name,
    total_steps: plan.steps.length,
    step_index: i,
    step: step,
    retryCount: 0,
    verification
  }
}));

const item = $('Loop Steps').first().json;
const fileResp = $input.first().json;

let existing = null;
let fileSha = null;
if (fileResp.content && fileResp.encoding === 'base64') {
  existing = Buffer.from(fileResp.content, 'base64').toString('utf-8');
  fileSha = fileResp.sha;
}

return {
  json: {
    ...item,
    existingContent: existing,
    fileSha
  }
};

