const prev = $('Normalize Code').first().json;
const resp = $input.first().json;
const text = resp.content?.[0]?.text || '';

let review;
try {
  const m = text.match(/```(?:json)?\n?([\s\S]*?)\n?```/);
  review = JSON.parse(m ? m[1] : text);
} catch {
  review = { verdict: 'PASS', criteria_results: [], feedback: '' };
}

const passed = review.verdict === 'PASS';
const retryCount = prev.retryCount || 0;
const canRetry = prev.mode === 'ralph' && retryCount < prev.maxRetries;

return {
  json: {
    ...prev,
    verdict: review.verdict,
    reviewFeedback: review.feedback || '',
    criteriaResults: review.criteria_results || [],
    passed,
    retryCount: passed ? 0 : retryCount + 1,
    shouldRetry: !passed && canRetry,
    reviewerFeedback: !passed ? review.feedback : null
  }
};

// Feed back to executor with reviewer feedback
const item = $input.first().json;
return {
  json: {
    ...item,
    // reviewerFeedback is already set from Parse Review
  }
};

// Step done (pass or final fail), continue to next step in loop
const item = $input.first().json;
return {
  json: {
    step_id: item.step.step_id,
    file: item.step.target_file,
    verdict: item.verdict,
    feedback: item.reviewFeedback,
    verification: item.verification,
    branch_name: item.branch_name,
    repository: item.repository,
    mode: item.mode,
    maxRetries: item.maxRetries,
    retryCount: item.retryCount
  }
};

// Collect all step results
const results = $input.all().map(i => i.json);
const cmd = $('Parse Command').first().json;
const plan = $('Parse Plan → Split Steps').first().json;

const passed = results.filter(r => r.verdict === 'PASS').length;
const failed = results.filter(r => r.verdict === 'FAIL').length;
const total = results.length;

const verification = plan.verification || { commands: [] };

let status = failed === 0 ? '✅' : '⚠️';
let stepSummary = results.map(r => 
  `${r.verdict === 'PASS' ? '✅' : '❌'} Step ${r.step_id}: \`${r.file}\``
).join('\n');

return {
  json: {
    channelId: cmd.channelId,
    repository: cmd.repository,
    branch_name: plan.branch_name,
    mode: cmd.mode,
    maxRetries: cmd.maxRetries,
    verification,
    retryCount: Math.max(...results.map(r => r.retryCount || 0), 0),
    message: `${status} **Task ${failed === 0 ? 'Complete' : 'Finished with Issues'}** (${passed}/${total} passed)\n` +
      `> ${cmd.task}\n\n` +
      `${stepSummary}\n\n` +
      `📦 Branch: \`${plan.branch_name}\``,
    createPR: failed === 0
  }
};

