const summary = $('Summarize Results').first().json;
return {
  json: {
    channelId: summary.channelId,
    finalMsg: summary.message + '\n\n⚠️ Some steps failed. PR not created. Review and retry.'
  }
};

// Create a K8s Job to clone the branch and run verification commands
const item = $input.first().json;
const cmds = item.verification.commands || [];
const image = item.verification.image || ($env.K8S_RUNNER_IMAGE || 'dev-team-runner:latest');
const branch = item.branch_name;
const repo = item.repository;
const jobName = 'verify-' + branch.replace(/\//g, '-').slice(0, 40) + '-' + Date.now();

const manifest = {
  apiVersion: 'batch/v1',
  kind: 'Job',
  metadata: {
    name: jobName,
    namespace: $env.K8S_NAMESPACE || 'dev-team',
    labels: {
      app: 'dev-team-verify',
      branch: branch.replace(/\//g, '-').slice(0, 63)
    }
  },
  spec: {
    ttlSecondsAfterFinished: 3600,
    backoffLimit: 0,
    activeDeadlineSeconds: 600,
    template: {
      metadata: {
        labels: {
          app: 'dev-team-verify',
          'job-name': jobName
        }
      },
      spec: {
        restartPolicy: 'Never',
        containers: [{
          name: 'verify',
          image: image,
          command: ['/bin/sh', '-c'],
          args: [
            `git config --global url."https://\${GITHUB_TOKEN}@github.com/".insteadOf "https://github.com/" && ` +
            `git clone --branch ${branch} --single-branch --depth 1 https://github.com/${repo}.git /workspace && ` +
            `cd /workspace && ` +
            `if [ -f requirements.txt ]; then pip install -q -r requirements.txt; fi && ` +
            `if [ -f package.json ]; then npm ci --silent; fi && ` +
            cmds.join(' && ')
          ],
          env: [
            { name: 'GITHUB_TOKEN', value: $env.GITHUB_TOKEN || '' }
          ],
          resources: {
            limits: { cpu: '1', memory: '2Gi' },
            requests: { cpu: '500m', memory: '1Gi' }
          }
        }]
      }
    }
  }
};

return {
  json: {
    ...item,
    jobName,
    k8sNamespace: $env.K8S_NAMESPACE || 'dev-team',
    jobManifest: manifest
  }
};

const jobStatus = $('Check Job Status').first().json;
const logsRaw = $input.first().json;
const prev = $('Build K8s Job Manifest').first().json;

// Logs may be a string or in .data
const logs = typeof logsRaw === 'string' ? logsRaw : (logsRaw.data || JSON.stringify(logsRaw));

const succeeded = (jobStatus.status?.succeeded || 0) >= 1;
const retryCount = prev.retryCount || 0;
const canRetry = prev.mode === 'ralph' && retryCount < prev.maxRetries;

return {
  json: {
    ...prev,
    verificationPassed: succeeded,
    verificationLogs: typeof logs === 'string' ? logs.slice(0, 3000) : JSON.stringify(logs).slice(0, 3000),
    retryCount: succeeded ? retryCount : retryCount + 1,
    shouldRetryVerification: !succeeded && canRetry
  }
};

// Feed verification errors back to the executor for all steps
const item = $input.first().json;
const planSteps = $('Parse Plan → Split Steps').all().map(i => i.json);

return planSteps.map(stepItem => ({
  json: {
    ...stepItem,
    retryCount: item.retryCount,
    reviewerFeedback: 'VERIFICATION FAILED. Fix the code so these commands pass:\n' +
      'Commands: ' + (item.verification.commands || []).join(', ') + '\n\n' +
      'Error output:\n' + (item.verificationLogs || '(no logs)').slice(0, 2000)
  }
}));

const item = $input.first().json;
return {
  json: {
    channelId: item.channelId,
    finalMsg: item.message + '\n\n❌ **Verification failed** (retries exhausted)\n```\n' + (item.verificationLogs || '(no logs)').slice(0, 1500) + '\n```'
  }
};
